b82f6\",\"TOM4.mp3\",8,true),\n      sg(\"Conga Hi\",\"#6366f1\",\"CONGA_HI.mp3\",-16,true),sg(\"Conga Low\",\"#8b5cf6\",\"CONGA_LOW.mp3\",16,true),sg(\"Baixo\",\"#22c55e\",\"BASS-01.mp3\",0,false),sg(\"Guitarra\",\"#14b8a6\",\"GT.mp3\",-20,true),\n      sg(\"Violão\",\"#f59e0b\",\"AC.mp3\",20,true),sg(\"Voz (Dany)\",\"#ec4899\",\"DANY.mp3\",0,true)]},\n    {label:\"Forró Pra Recordar (c/ voz)\", folder:\"mix-forro-recordar\", stems:[\n      sg(\"Bumbo\",\"#ef4444\",\"1-BB.mp3\",0,false),sg(\"Caixa\",\"#f97316\",\"2-CX.mp3\",0,true),sg(\"Chimbal\",\"#84cc16\",\"3-HH.mp3\",-14,true),sg(\"Tom 1\",\"#eab308\",\"4-TOM1.mp3\",-8,true),\n      sg(\"Tom 2\",\"#22c55e\",\"5-TOM2.mp3\",8,true),sg(\"Surdo\",\"#14b8a6\",\"6-SD.mp3\",-6,false),sg(\"Conga 1\",\"#06b6d4\",\"7-CG1.mp3\",-16,true),sg(\"Conga 2\",\"#3b82f6\",\"8-CG2.mp3\",16,true),\n      sg(\"Baixo\",\"#22c55e\",\"9-BASS.mp3\",0,false),sg(\"Guitarra\",\"#14b8a6\",\"10-GT.mp3\",-20,true),sg(\"Sanfona\",\"#f59e0b\",\"11-AC.mp3\",20,true),sg(\"Teclado\",\"#6366f1\",\"12-KEY.mp3\",-10,false),\n      sg(\"Sax\",\"#fbbf24\",\"13-SAX.mp3\",10,true),sg(\"Voz\",\"#ec4899\",\"14-VOZ.mp3\",0,true)]}\n  ];\n  let ac=null,masterGain=null,lim=null,masterAn=null,playing=false,curSong=0,loadTok=0,realSources=[];\n  let fxRack=null; // racks de efeito (reverb + delay)\n  const bufCache={},aNodes=[];\n  function dbToLin(db){return db<=FMIN?0:Math.pow(10,db/20);}\n  // Gera um impulso sintético para o ConvolverNode (reverb hall) com decaimento exp\n  function makeImpulse(seconds){\n    const rate=ac.sampleRate, len=Math.max(1,Math.floor(clamp(seconds,0.2,5)*rate)), buf=ac.createBuffer(2,len,rate);\n    for(let ch=0;ch<2;ch++){ const d=buf.getChannelData(ch);\n      for(let i=0;i<len;i++){ d[i]=(Math.random()*2-1)*Math.pow(1-i/len,2.4); } }\n    return buf;\n  }\n  function buildAudioGraph(){\n    ac=new (window.AudioContext||window.webkitAudioContext)();\n    masterGain=ac.createGain();masterGain.gain.value=dbToLin(state.master);\n    lim=ac.createDynamicsCompressor();lim.threshold.value=-3;lim.ratio.value=12;lim.attack.value=0.003;lim.release.value=0.12;\n    masterGain.connect(lim);lim.connect(ac.destination);\n    masterAn=ac.createAnalyser();masterAn.fftSize=256;masterAn._buf=new Float32Array(masterAn.fftSize);lim.connect(masterAn);\n    // ---- Racks de efeito: Reverb (Convolver) + Delay c/ feedback, retornando ao master ----\n    const revIn=ac.createGain(), conv=ac.createConvolver(), revRet=ac.createGain();\n    conv.buffer=makeImpulse(state.fx.revSize); revRet.gain.value=state.fx.revMix;\n    revIn.connect(conv);conv.connect(revRet);revRet.connect(masterGain);\n    const dlyIn=ac.createGain(), dly=ac.createDelay(1.5), dfb=ac.createGain(), dlyRet=ac.createGain();\n    dly.delayTime.value=state.fx.dlyTime; dfb.gain.value=state.fx.dlyFb; dlyRet.gain.value=state.fx.dlyMix;\n    dlyIn.connect(dly);dly.connect(dfb);dfb.connect(dly);dly.connect(dlyRet);dlyRet.connect(masterGain);\n    fxRack={revIn,conv,revRet,dlyIn,dly,dfb,dlyRet};\n    for(let i=0;i<24;i++){\n      const trim=ac.createGain();\n      const hpf=ac.createBiquadFilter();hpf.type=\"highpass\";hpf.frequency.value=20;hpf.Q.value=0.707;\n      // EQ 4 bandas: lowshelf, peaking, peaking, highshelf\n      const eq0=ac.createBiquadFilter();eq0.type=\"lowshelf\";\n      const eq1=ac.createBiquadFilter();eq1.type=\"peaking\";\n      const eq2=ac.createBiquadFilter();eq2.type=\"peaking\";\n      const eq3=ac.createBiquadFilter();eq3.type=\"highshelf\";\n      const lpf=ac.createBiquadFilter();lpf.type=\"lowpass\";lpf.frequency.value=20000;lpf.Q.value=0.707;\n      const preAn=ac.createAnalyser();preAn.fftSize=256;\n      const gate=ac.createGain();gate.gain.value=1;\n      const comp=ac.createDynamicsCompressor();comp.threshold.value=0;comp.ratio.value=1;comp.attack.value=0.005;comp.release.value=0.15;comp.knee.value=0;\n      const mk=ac.createGain();mk.gain.value=1;           // OUT GAIN (makeup) do comp\n      const fdr=ac.createGain();fdr.gain.value=0;\n      const pan=ac.createStereoPanner();\n      const an=ac.createAnalyser();an.fftSize=256;\n      const revSend=ac.createGain();revSend.gain.value=0;\n      const dlySend=ac.createGain();dlySend.gain.value=0;\n      // cadeia: source→trim→HPF→EQ0→EQ1→EQ2→EQ3→LPF→(preAn tap)→gate→comp→mk→fader→pan→master\n      trim.connect(hpf);hpf.connect(eq0);eq0.connect(eq1);eq1.connect(eq2);eq2.connect(eq3);eq3.connect(lpf);\n      lpf.connect(preAn); lpf.connect(gate); gate.connect(comp);comp.connect(mk);mk.connect(fdr);\n      fdr.connect(pan);pan.connect(masterGain);fdr.connect(an);\n      fdr.connect(revSend);revSend.connect(revIn); fdr.connect(dlySend);dlySend.connect(dlyIn);\n      aNodes[i]={trim,hpf,eq:[eq0,eq1,eq2,eq3],lpf,preAn,preBuf:new Float32Array(preAn.fftSize),gate,comp,mk,fdr,pan,an,buf:new Float32Array(an.fftSize),revSend,dlySend};\n    }\n    for(let i=0;i<24;i++) applyChanAudio(i);\n  }\n  function applyChanAudio(i){\n    if(!ac||!aNodes[i])return;const n=aNodes[i],c=CH[i],t=ac.currentTime;\n    n.trim.gain.setTargetAtTime(dbToLin(c.gain-16),t,0.02);           // head-amp relativo ao unity (gain ~16 = 0 dB)\n    n.hpf.frequency.setTargetAtTime(c.hpfOn?c.hpf:20,t,0.02);\n    n.lpf.frequency.setTargetAtTime(c.lpfOn?c.lpf:20000,t,0.02);\n    // EQ 4 bandas -> os 4 BiquadFilters\n    const kf=eqTypeFactor(c.eqType);\n    c.eq.forEach((b,bi)=>{ const f=n.eq[bi]; if(f.type!==b.type) f.type=b.type;\n      f.frequency.setTargetAtTime(clamp(b.f,20,20000),t,0.02);\n      f.gain.setTargetAtTime(b.g,t,0.02);\n      f.Q.setTargetAtTime(clamp(b.q*kf,0.05,18),t,0.02); });\n    // Comp (Dynamics 2) via DynamicsCompressor\n    if(c.compOn){ n.comp.threshold.value=c.compThr; n.comp.ratio.value=(c.compRatio>=40?20:Math.max(1,c.compRatio));\n      n.comp.attack.value=clamp(c.compAtk/1000,0,0.12); n.comp.release.value=clamp(c.compRel/1000,0.005,1.5);\n      n.comp.knee.value=(c.compKnee===''HARD''||c.compKnee===0)?0:clamp(c.compKnee*4,0,30);\n      n.mk.gain.setTargetAtTime(dbToLin(c.compGain),t,0.02);\n    } else { n.comp.threshold.value=0; n.comp.ratio.value=1; n.mk.gain.setTargetAtTime(1,t,0.02); }\n    n.pan.pan.setTargetAtTime(clamp(c.pan/63,-1,1),t,0.02);\n    // DCA + MUTE groups (VCA: multiplica o ganho do fader; mute zera)\n    let dcaLin=1, muted=false;\n    for(let g=0;g<N_DCA;g++){ if(c.dca[g]){ if(!state.dcaOn[g]) muted=true; dcaLin*=dbToLin(state.dcaGain[g]); } }\n    for(let g=0;g<N_MUTE;g++){ if(c.mute[g] && state.muteActive[g]) muted=true; }\n    const audible=c.on&&!muted&&c.fader>FMIN&&c.hasAudio;\n    n.fdr.gain.setTargetAtTime(audible?dbToLin(c.fader)*dcaLin:0,t,0.02);\n    // envios para os racks de efeito (pós-fader)\n    n.revSend.gain.setTargetAtTime((c.hasAudio&&c.fxRev>FMIN)?dbToLin(c.fxRev):0,t,0.02);\n    n.dlySend.gain.setTargetAtTime((c.hasAudio&&c.fxDly>FMIN)?dbToLin(c.fxDly):0,t,0.02);\n  }\n  function applyFX(){ if(!ac||!fxRack)return; const t=ac.currentTime;\n    fxRack.revRet.gain.setTargetAtTime(state.fx.revMix,t,0.03);\n    fxRack.dly.delayTime.setTargetAtTime(clamp(state.fx.dlyTime,0,1.5),t,0.03);\n    fxRack.dfb.gain.setTargetAtTime(clamp(state.fx.dlyFb,0,0.9),t,0.03);\n    fxRack.dlyRet.gain.setTargetAtTime(state.fx.dlyMix,t,0.03); }\n  // Processa os gates (ducking) a cada frame lendo o nível pré-dinâmica de cada canal\n  function processGates(){\n    if(!ac)return; const t=ac.currentTime;\n    for(let i=0;i<24;i++){ const n=aNodes[i], c=CH[i]; if(!n)continue;\n      if(!c.gateOn || !playing || !c.hasAudio){ n.gate.gain.setTargetAtTime(1,t,0.01); c._gr=0; continue; }\n      n.preAn.getFloatTimeDomainData(n.preBuf);\n      let s=0; for(let k=0;k<n.preBuf.length;k++)s+=n.preBuf[k]*n.preBuf[k];\n      const rms=Math.sqrt(s/n.preBuf.length), db=rms>1e-5?20*Math.log10(rms):-90;\n      const open=db>c.gateThr, target=open?1:dbToLin(c.gateRange);\n      const tc=Math.max(0.004,(open?c.gateAtk:c.gateDecay)/1000/3);\n      n.gate.gain.setTargetAtTime(target,t,tc);\n      c._gr=open?0:Math.max(0,-c.gateRange);\n    }\n  }\n  function applyMasterAudio(){ if(ac&&masterGain) masterGain.gain.setTargetAtTime(dbToLin(state.master),ac.currentTime,0.02); }\n  // ---- SCENES: snapshot/restauração completa ----\n  function snapCh(c){ return JSON.parse(JSON.stringify({gain:c.gain,hpfOn:c.hpfOn,hpf:c.hpf,lpfOn:c.lpfOn,lpf:c.lpf,\n    eq:c.eq,eqType:c.eqType,gateOn:c.gateOn,gateThr:c.gateThr,gateRange:c.gateRange,gateAtk:c.gateAtk,gateHold:c.gateHold,gateDecay:c.gateDecay,\n    compOn:c.compOn,compThr:c.compThr,compRatio:c.compRatio,compAtk:c.compAtk,compRel:c.compRel,compKnee:c.compKnee,compGain:c.compGain,\n    pan:c.pan,fader:c.fader,on:c.on,sends:c.sends,sendOn:c.sendOn,sendPre:c.sendPre,dca:c.dca,mute:c.mute,fxRev:c.fxRev,fxDly:c.fxDly})); }\n  function storeScene(slot){ scenes[slot]={ ch:CH.map(snapCh), master:state.master,\n    dcaGain:state.dcaGain.slice(), dcaOn:state.dcaOn.slice(), muteActive:state.muteActive.slice(),\n    fx:JSON.parse(JSON.stringify(state.fx)), ts:Date.now() }; toast(\"Cena \"+(slot+1)+\" armazenada ✔\"); }\n  function recallScene(slot){ const s=scenes[slot]; if(!s){ toast(\"Cena \"+(slot+1)+\" vazia\"); return; }\n    s.ch.forEach((sc,i)=>{ Object.assign(CH[i],JSON.parse(JSON.stringify(sc))); });\n    state.master=s.master; state.dcaGain=s.dcaGain.slice(); state.dcaOn=s.dcaOn.slice();\n    state.muteActive=s.muteActive.slice(); state.fx=JSON.parse(JSON.stringify(s.fx));\n    if(fxRack) fxRack.conv.buffer=makeImpulse(state.fx.revSize);\n    for(let i=0;i<24;i++) applyChanAudio(i); applyMasterAudio(); applyFX();\n    paintStrips(); paintSelected(); drawScreen(); toast(\"Cena \"+(slot+1)+\" recuperada ▸ faders atualizados\"); }\n  function chLevelDb(i){ if(!ac||!aNodes[i])return -90; const n=aNodes[i]; n.an.getFloatTimeDomainData(n.buf);\n    let s=0; for(let k=0;k<n.buf.length;k++)s+=n.buf[k]*n.buf[k]; const rms=Math.sqrt(s/n.buf.length); return rms>1e-5?20*Math.log10(rms):-90; }\n  function masterLevelDb(){ if(!masterAn)return -90; masterAn.getFloatTimeDomainData(masterAn._buf);\n    let s=0; for(let k=0;k<masterAn._buf.length;k++)s+=masterAn._buf[k]*masterAn._buf[k]; const rms=Math.sqrt(s/masterAn._buf.length); return rms>1e-5?20*Math.log10(rms):-90; }\n  async function loadBuf(url){ if(bufCache[url])return bufCache[url]; const r=await fetch(url); if(!r.ok)throw new Error(\"HTTP \"+r.status); const ab=await r.arrayBuffer(); const b=await ac.decodeAudioData(ab); bufCache[url]=b; return b; }\n  function setStatus(txt,col){ const el=$(\"#audioStatus\"); if(el){el.textContent=\"áudio: \"+txt; el.style.color=col||\"var(--muted)\";} }\n  function loadSong(idx){\n    curSong=idx; const song=SONGS[idx];\n    for(let i=0;i<24;i++){ const st=song.stems[i], c=CH[i];\n      if(st){ c.name=st.n; c.color=st.c; c.file=st.f; c.pan=st.p; c.hpfOn=st.h; c.hpf=st.h?100:80; c.hasAudio=true; c.on=true; c.fader=-3; c.gain=16; }\n      else { c.name=\"—\"; c.color=\"#334155\"; c.file=null; c.hasAudio=false; c.on=false; } }\n    buildStrips(); wireKnobs(); paintStrips(); paintSelected(); drawScreen();\n    if(ac){ for(let i=0;i<24;i++) applyChanAudio(i); }\n  }\n  function setPlayBtn(on){ const b=$(\"#playBtn\"); if(b){ b.textContent=on?\"⏸ Parar\":\"▶ Tocar base\"; b.style.background=on?\"#ef4444\":\"#22c55e\"; } }\n  async function playSong(){\n    if(!ac) buildAudioGraph();\n    if(ac.state===\"suspended\"){ try{await ac.resume();}catch(e){} }\n    const song=SONGS[curSong], base=SB+song.folder+\"/\", tok=++loadTok;\n    setStatus(\"carregando \"+song.label+\"…\",\"#f59e0b\");\n    let bufs;\n    try{ bufs=await Promise.all(song.stems.map(st=>loadBuf(base+st.f))); }\n    catch(e){ setStatus(\"erro: \"+e.message,\"#ef4444\"); return; }\n    if(tok!==loadTok) return;\n    stopSong(true);\n    const t0=ac.currentTime+0.12;\n    song.stems.forEach((st,i)=>{ if(i>=24||!aNodes[i])return; const src=ac.createBufferSource(); src.buffer=bufs[i]; src.loop=true; src.connect(aNodes[i].trim); src.start(t0); realSources.push(src); });\n    for(let i=0;i<24;i++) applyChanAudio(i);\n    playing=true; setPlayBtn(true); setStatus(\"tocando ♪ \"+song.label,\"#22c55e\");\n  }\n  function stopSong(keep){ realSources.forEach(s=>{try{s.stop();}catch(e){}}); realSources=[]; playing=false; setPlayBtn(false); if(!keep) setStatus(\"parado\"); }\n\n  // ---------------- INIT ----------------\n  // Seletor de música + botão Play\n  (function initAudioUI(){\n    const sel=$(\"#songSel\"); if(sel){ SONGS.forEach((s,i)=>{ const o=document.createElement(\"option\"); o.value=i; o.textContent=s.label; sel.appendChild(o); });\n      sel.value=0; sel.onchange=()=>{ const wasPlaying=playing; stopSong(true); loadSong(+sel.value); if(wasPlaying) playSong(); }; }\n    const pb=$(\"#playBtn\"); if(pb){ pb.onclick=()=>{ if(playing) stopSong(); else playSong(); }; }\n  })();\n  loadSong(0);\n  try{ buildAudioGraph(); }catch(e){}   // cria o AudioContext no load (igual mix-show); resume no 1º play\n  updateSof(); paintMission();\n  window.addEventListener(\"resize\",sizeCanvas);\n  setTimeout(sizeCanvas,30);\n  requestAnimationFrame(loop);\n  // Dante LED blink\n  setInterval(()=>{ const l=$(\"#danteLed\"); l.classList.toggle(\"warn\"); setTimeout(()=>l.classList.remove(\"warn\"),120); },4000);\n\n  // ---------- FIT: escala o console p/ caber (zoom, ciente de layout) ; empilha no celular ----------\n  function fitConsole(){\n    const con=document.querySelector(''.console''); if(!con) return;\n    const DW=1360, DH=672, vw=window.innerWidth, vh=window.innerHeight;\n    if(vw < 520){ document.body.classList.add(''stacked''); con.classList.add(''stacked''); con.style.zoom='''';\n      document.body.style.alignItems=''flex-start''; }\n    else{ document.body.classList.remove(''stacked''); con.classList.remove(''stacked'');\n      // O player embute o simulador num iframe 16:9. Em tela cheia, esse iframe fica MAIS ALTO que a\n      // tela real (ex.: vh=1421 mas a tela só tem 1038) — a base fica fora da tela. Então NÃO usamos\n      // a altura do iframe (window.innerHeight): usamos a altura REAL da tela (screen.height) menos o\n      // cabeçalho do player, e alinhamos ao topo. Assim o console (incl. faders e botões) cabe inteiro.\n      const scrH = (window.screen && screen.height) || vh;\n      const iframeTallerThanScreen = vh > scrH + 8;      // player 16:9 estourou a tela = fullscreen real\n      const visH = Math.min(vh, scrH);\n      const headerAllow = iframeTallerThanScreen ? 84 : (vh > 700 ? 40 : 6);\n      const effVh = Math.max(240, visH - headerAllow);\n      document.body.style.alignItems = (iframeTallerThanScreen || vh > 700) ? ''flex-start'' : ''center'';\n      let s=Math.min(vw/DW, effVh/DH); s=Math.max(0.4, Math.min(s, 2.4)); con.style.zoom=s; }\n    try{ sizeCanvas(); }catch(e){}\n  }\n  window.addEventListener(''resize'', fitConsole);\n  setTimeout(fitConsole, 45);\n})();\n</script>\n</body>\n</html>\n"}]'::jsonb);

